34	    public Response handle(String action, JsonNode request, String region) {
35	        return switch (action) {
36	            case "CreateUserPool" -> handleCreateUserPool(request, region);
37	            case "DescribeUserPool" -> handleDescribeUserPool(request);
38	            case "ListUserPools" -> handleListUserPools(request);
39	            case "UpdateUserPool" -> handleUpdateUserPool(request, region);
40	            case "GetUserPoolMfaConfig" -> handleGetUserPoolMfaConfig(request);
41	            case "DeleteUserPool" -> handleDeleteUserPool(request);
42	            case "CreateUserPoolClient" -> handleCreateUserPoolClient(request);
43	            case "DescribeUserPoolClient" -> handleDescribeUserPoolClient(request);
44	            case "ListUserPoolClients" -> handleListUserPoolClients(request);
45	            case "DeleteUserPoolClient" -> handleDeleteUserPoolClient(request);
46	            case "CreateResourceServer" -> handleCreateResourceServer(request);
47	            case "DescribeResourceServer" -> handleDescribeResourceServer(request);
48	            case "ListResourceServers" -> handleListResourceServers(request);
49	            case "UpdateResourceServer" -> handleUpdateResourceServer(request);
50	            case "DeleteResourceServer" -> handleDeleteResourceServer(request);
51	            case "AdminCreateUser" -> handleAdminCreateUser(request);
52	            case "AdminGetUser" -> handleAdminGetUser(request);
53	            case "AdminDeleteUser" -> handleAdminDeleteUser(request);
54	            case "AdminSetUserPassword" -> handleAdminSetUserPassword(request);
55	            case "AdminUpdateUserAttributes" -> handleAdminUpdateUserAttributes(request);
56	            case "AdminUserGlobalSignOut" -> handleAdminUserGlobalSignOut(request);
57	            case "ListUsers" -> handleListUsers(request);
58	            case "InitiateAuth" -> handleInitiateAuth(request);
59	            case "AdminInitiateAuth" -> handleAdminInitiateAuth(request);
60	            case "RespondToAuthChallenge" -> handleRespondToAuthChallenge(request);
61	            case "SignUp" -> handleSignUp(request);
62	            case "ConfirmSignUp" -> handleConfirmSignUp(request);
63	            case "ChangePassword" -> handleChangePassword(request);
64	            case "ForgotPassword" -> handleForgotPassword(request);
65	            case "ConfirmForgotPassword" -> handleConfirmForgotPassword(request);
66	            case "GetUser" -> handleGetUser(request);
67	            case "UpdateUserAttributes" -> handleUpdateUserAttributes(request);
68	            case "CreateGroup" -> handleCreateGroup(request);
69	            case "GetGroup" -> handleGetGroup(request);
70	            case "ListGroups" -> handleListGroups(request);
71	            case "DeleteGroup" -> handleDeleteGroup(request);
72	            case "AdminAddUserToGroup" -> handleAdminAddUserToGroup(request);
73	            case "AdminRemoveUserFromGroup" -> handleAdminRemoveUserFromGroup(request);
74	            case "AdminListGroupsForUser" -> handleAdminListGroupsForUser(request);
75	            case "GetTokensFromRefreshToken" -> handleGetTokensFromRefreshToken(request);
76	            default -> Response.status(400)
77	                    .entity(new AwsErrorResponse("UnsupportedOperation", "Operation " + action + " is not supported."))
78	                    .build();
79	        };
80	    }
