82	    private Response handleCreateUserPool(JsonNode request, String region) {
83	        @SuppressWarnings("unchecked")
84	        Map<String, Object> reqMap = objectMapper.convertValue(request, Map.class);
85	        UserPool pool = service.createUserPool(reqMap, region);
86	        ObjectNode response = objectMapper.createObjectNode();
87	        response.set("UserPool", userPoolToFullNode(pool));
88	        return Response.ok(response).build();
