468	    private ObjectNode clientToNode(UserPoolClient c) {
469	        ObjectNode node = objectMapper.createObjectNode();
470	        node.put("ClientId", c.getClientId());
471	        node.put("UserPoolId", c.getUserPoolId());
472	        node.put("ClientName", c.getClientName());
473	        if (c.getClientSecret() != null) {
474	            node.put("ClientSecret", c.getClientSecret());
475	        }
476	        node.put("GenerateSecret", c.isGenerateSecret());
477	        node.put("AllowedOAuthFlowsUserPoolClient", c.isAllowedOAuthFlowsUserPoolClient());
478	        ArrayNode flows = node.putArray("AllowedOAuthFlows");
479	        c.getAllowedOAuthFlows().forEach(flows::add);
480	        ArrayNode scopes = node.putArray("AllowedOAuthScopes");
481	        c.getAllowedOAuthScopes().forEach(scopes::add);
482	        node.put("CreationDate", c.getCreationDate());
483	        node.put("LastModifiedDate", c.getLastModifiedDate());
484	        return node;
485	    }
