487	    private ObjectNode resourceServerToNode(ResourceServer server) {
488	        ObjectNode node = objectMapper.createObjectNode();
489	        node.put("UserPoolId", server.getUserPoolId());
490	        node.put("Identifier", server.getIdentifier());
491	        node.put("Name", server.getName());
492	        node.put("CreationDate", server.getCreationDate());
493	        node.put("LastModifiedDate", server.getLastModifiedDate());
494	        ArrayNode scopes = node.putArray("Scopes");
495	        for (ResourceServerScope scope : server.getScopes()) {
496	            ObjectNode item = scopes.addObject();
497	            item.put("ScopeName", scope.getScopeName());
498	            if (scope.getScopeDescription() != null) {
499	                item.put("ScopeDescription", scope.getScopeDescription());
500	            }
501	        }
502	        return node;
503	    }
504	
505	    private List<ResourceServerScope> parseScopes(JsonNode scopesNode) {
506	        if (scopesNode == null || !scopesNode.isArray()) {
507	            return List.of();
508	        }
509	
510	        List<ResourceServerScope> scopes = new java.util.ArrayList<>();
511	        scopesNode.forEach(item -> {
512	            ResourceServerScope scope = new ResourceServerScope();
513	            scope.setScopeName(item.path("ScopeName").asText());
514	            scope.setScopeDescription(item.path("ScopeDescription").asText(null));
515	            scopes.add(scope);
516	        });
517	        return scopes;
518	    }
