        clientReq.put("GenerateSecret", true);
        JsonNode clientBody = (JsonNode) handler.handle("CreateUserPoolClient", clientReq, "us-east-1").getEntity();
        String clientId = clientBody.get("UserPoolClient").get("ClientId").asText();

        // List clients
        ObjectNode listReq = mapper.createObjectNode();
        listReq.put("UserPoolId", poolId);
        Response response = handler.handle("ListUserPoolClients", listReq, "us-east-1");
        assertEquals(200, response.getStatus());

        JsonNode body = (JsonNode) response.getEntity();
        JsonNode clients = body.get("UserPoolClients");
        assertEquals(1, clients.size());

        JsonNode client = clients.get(0);
        // Per AWS spec, only ClientId, ClientName, and UserPoolId should be present
        Set<String> expectedFields = Set.of("ClientId", "ClientName", "UserPoolId");
        Set<String> actualFields = new java.util.HashSet<>();
        client.fieldNames().forEachRemaining(actualFields::add);

        assertEquals(expectedFields, actualFields,
                "ListUserPoolClients response should only contain ClientId, ClientName, and UserPoolId");

        assertNotNull(client.get("ClientId"));
        assertNotNull(client.get("ClientName"));
        assertNotNull(client.get("UserPoolId"));

        // These fields should NOT be present in ListUserPoolClients response
        assertTrue(client.get("ClientSecret") == null || client.get("ClientSecret").isNull(),
                "ClientSecret should not be in ListUserPoolClients response");
        assertTrue(client.get("GenerateSecret") == null || client.get("GenerateSecret").isNull(),
                "GenerateSecret should not be in ListUserPoolClients response");
        assertTrue(client.get("AllowedOAuthFlowsUserPoolClient") == null || client.get("AllowedOAuthFlowsUserPoolClient").isNull(),
                "AllowedOAuthFlowsUserPoolClient should not be in ListUserPoolClients response");
        assertTrue(client.get("CreationDate") == null || client.get("CreationDate").isNull(),
                "CreationDate should not be in ListUserPoolClients response");
        assertTrue(client.get("LastModifiedDate") == null || client.get("LastModifiedDate").isNull(),
                "LastModifiedDate should not be in ListUserPoolClients response");
    }

    @Test
    void createUserPoolReturnsRichResponse() {
        ObjectNode request = mapper.createObjectNode();
        request.put("PoolName", "test-pool");
        ArrayNode schema = request.putArray("Schema");
        ObjectNode attr = schema.addObject();
        attr.put("Name", "email");
        attr.put("AttributeDataType", "String");

        Response response = handler.handle("CreateUserPool", request, "us-east-1");
        assertEquals(200, response.getStatus());

        JsonNode body = (JsonNode) response.getEntity();
        JsonNode pool = body.get("UserPool");

        assertNotNull(pool.get("Id"));
        assertEquals("test-pool", pool.get("Name").asText());
        assertTrue(pool.get("Arn").asText().contains("arn:aws:cognito-idp:us-east-1:000000000000:userpool/"));
        assertEquals("Enabled", pool.get("Status").asText());

        // Check mandatory blocks for Terraform
        assertNotNull(pool.get("SchemaAttributes"));
        assertEquals(1, pool.get("SchemaAttributes").size());
        assertEquals("email", pool.get("SchemaAttributes").get(0).get("Name").asText());

        assertNotNull(pool.get("Policies"));
        assertNotNull(pool.get("LambdaConfig"));
        assertNotNull(pool.get("AdminCreateUserConfig"));
        assertNotNull(pool.get("AccountRecoverySetting"));
        assertEquals("ESSENTIALS", pool.get("UserPoolTier").asText());
    }
}

